az-001.implementationNotes:
# Check MFA registration status
Connect-MgGraph -Scopes 'UserAuthenticationMethod.Read.All','Reports.Read.All'

# Get MFA registration report
Get-MgReportAuthenticationMethodUserRegistrationDetail -All | Select UserPrincipalName, IsMfaRegistered, MethodsRegistered | Where-Object { $_.IsMfaRegistered -eq $false } | Format-Table

# Create Conditional Access policy requiring MFA for all users
$params = @{
  displayName = 'Require MFA for All Users'
  state = 'enabledForReportingButNotEnforced'  # Start in report-only
  conditions = @{
    users = @{ includeUsers = @('All'); excludeUsers = @('<break-glass-id>') }
    applications = @{ includeApplications = @('All') }
  }
  grantControls = @{
    operator = 'OR'
    builtInControls = @('mfa')
  }
}
New-MgIdentityConditionalAccessPolicy @params
